function halfThicknessSvg(x) {
  return 5.6 + (64.4 * x) / 1000;
}

function perpendicularOffsetPx(progress, slot, sign) {
  if (sign === 0 || slot <= 0 || guideLineCount <= 0) {
    return 0;
  }
  const x = clamp(progress, 0, 1) * 1000;
  const half = halfThicknessSvg(x);
  const scaledGap = guideLineCentreGap * (half / 27.3);
  const ySvg = half + slot * scaledGap;
  const scale = window.innerWidth / 1000 * 0.52;
  return sign * ySvg * scale;
}

function guideSpacingPxAtProgress(progress) {
  const x = clamp(progress, 0, 1) * 1000;
  const half = halfThicknessSvg(x);
  const scaledGap = guideLineCentreGap * (half / 27.3);
  const scale = window.innerWidth / 1000 * 0.52;
  return scaledGap * scale;
}

function personalityHeightInZ(progress) {
  const baseProgress = 0.5;
  const baseSpacing = Math.max(guideSpacingPxAtProgress(baseProgress), 1e-6);
  const scaled = 25 * (guideSpacingPxAtProgress(progress) / baseSpacing);
  return clamp(scaled, 10, 80);
}

function readLineAngleDeg() {
  const raw = getComputedStyle(document.documentElement).getPropertyValue("--line-angle").trim();
  const value = parseFloat(raw);
  return Number.isFinite(value) ? value : 30;
}

/** Viewport (px): point on offset guideline parallel to timeline, at given viewport Y. */
function viewportPointOnOffsetGuide(cx, cy, thetaDeg, signedOffsetPx, vy) {
  const θ = (thetaDeg * Math.PI) / 180;
  const nx = -Math.sin(θ);
  const ny = Math.cos(θ);
  const ux = Math.cos(θ);
  const uy = Math.sin(θ);
  const cn = cx * nx + cy * ny;
  const target = cn + signedOffsetPx;
  if (Math.abs(nx) > 1e-4) {
    const x = (target - vy * ny) / nx;
    return { x, y: vy };
  }
  if (Math.abs(uy) > 1e-4) {
    const t = (vy - cy - signedOffsetPx * ny) / uy;
    return { x: cx + signedOffsetPx * nx + t * ux, y: vy };
  }
  return { x: cx + signedOffsetPx * nx, y: vy };
}

function layoutPersonalityGeometry(multiplier = 0) {
  if (!personalitiesLayer || !stage) {
    return;
  }
  const stageRect = stage.getBoundingClientRect();
  const q = readLineAngleDeg();
  const θ = (q * Math.PI) / 180;
  const cx = window.innerWidth / 2;
  const cy = window.innerHeight / 2;
  const w = stage.offsetWidth;
  const h = stage.offsetHeight;
  const eps = multiplier >= 0 ? 1 : -1;
  const zDeg = (q + 180 + eps * 90) / 3;
  const zRad = (zDeg * Math.PI) / 180;
  let zxBase = Math.cos(zRad);
  let zyBase = Math.sin(zRad);

  personalityShapes.forEach((shape) => {
    const { svg, poly, label, pBirth, pDeath, pMid, slot, sign, name } = shape;
    let zx = zxBase;
    let zy = zyBase;
    const signDir = sign > 0 ? 1 : sign < 0 ? -1 : 0;
    if (signDir !== 0) {
      const nOutX = signDir * -Math.sin(θ);
      const nOutY = signDir * Math.cos(θ);
      if (zx * nOutX + zy * nOutY < 0) {
        zx = -zx;
        zy = -zy;
      }
    }

    const vyA = stageRect.top + pBirth * h;
    const vyD = stageRect.top + pDeath * h;
    const guideOffset = perpendicularOffsetPx(pMid, slot, sign);
    const A = viewportPointOnOffsetGuide(cx, cy, q, guideOffset, vyA);
    const D = viewportPointOnOffsetGuide(cx, cy, q, guideOffset, vyD);

    const hBirth = personalityHeightInZ(pBirth);
    const hDeath = personalityHeightInZ(pDeath);

    const B = { x: A.x + hBirth * zx, y: A.y + hBirth * zy };
    const C = { x: D.x + hDeath * zx, y: D.y + hDeath * zy };

    const Ax = A.x - stageRect.left;
    const Ay = A.y - stageRect.top;
    const Bx = B.x - stageRect.left;
    const By = B.y - stageRect.top;
    const Cx = C.x - stageRect.left;
    const Cy = C.y - stageRect.top;
    const Dx = D.x - stageRect.left;
    const Dy = D.y - stageRect.top;

    if (poly) {
      poly.setAttribute("points", `${Ax},${Ay} ${Bx},${By} ${Cx},${Cy} ${Dx},${Dy}`);
    }

    if (label) {
      const adx = Dx - Ax;
      const ady = Dy - Ay;
      const adLen = Math.hypot(adx, ady) || 1;
      const baseAngleDeg = (Math.atan2(ady, adx) * 180) / Math.PI;
      const cxg = (Ax + Bx + Cx + Dx) / 4;
      const cyg = (Ay + By + Cy + Dy) / 4;
      const perpX = -ady / adLen;
      const perpY = adx / adLen;
      const zDotPerp = zx * perpX + zy * perpY;
      const flip = zDotPerp < 0 ? -1 : 1;
      const zpx = zx * flip;
      const zpy = zy * flip;
      const shear = clamp((zpx * adx + zpy * ady) / Math.max(adLen, 1e-6), -0.42, 0.42);
      label.setAttribute("transform", `translate(${cxg},${cyg}) rotate(${baseAngleDeg}) skewY(${(Math.atan(shear) * 180) / Math.PI})`);
      label.setAttribute("text-anchor", "middle");
      label.setAttribute("dominant-baseline", "middle");
      const maxChars = Math.max(5, Math.floor(adLen / 5.2));
      label.textContent = name.length > maxChars ? `${name.slice(0, maxChars - 1)}…` : name;
    }

    svg.setAttribute("viewBox", `0 0 ${w} ${h}`);
  });
}

function scoreOnDate(person, monthValue) {
  if (person.scoreSegments && person.scoreSegments.length) {
    const target = monthToNumber(monthValue);
    for (let index = 0; index < person.scoreSegments.length; index += 1) {
      const segment = person.scoreSegments[index];
      if (target >= monthToNumber(segment.start) && target <= monthToNumber(segment.end)) {
        return Number(segment.score) || 0;
      }
    }
  }
  return Number(person.leaningScore) || 0;
}

function primaryPartyAt(person, monthValue) {
  const target = monthToNumber(monthValue);
  const affiliations = (person.partyAffiliations || []).filter((row) => row.partyId);
  const active = affiliations.filter((row) => target >= monthToNumber(row.start) && target <= monthToNumber(row.end));
  if (!active.length) {
    return "";
  }
  return active.sort((a, b) => monthToNumber(a.start) - monthToNumber(b.start))[0].partyId;
}

function midMonth(start, end) {
  const middle = Math.round((monthToNumber(start) + monthToNumber(end)) / 2);
  return numberToMonth(middle);
}

function boundaryMonths(person) {
  const birth = person.birthDate;
  const death = person.deathDate;
  const set = new Set([birth, death]);
  (person.scoreSegments || []).forEach((segment) => {
    set.add(segment.start);
    set.add(segment.end);
  });
  return Array.from(set)
    .filter((month) => monthToNumber(month) >= monthToNumber(birth) && monthToNumber(month) <= monthToNumber(death))
    .sort((a, b) => monthToNumber(a) - monthToNumber(b));
}

function lifeChunks(person) {
  const bounds = boundaryMonths(person);
  if (bounds.length < 2) {
    return [{ start: person.birthDate, end: person.deathDate }];
  }
  const chunks = [];
  for (let index = 0; index < bounds.length - 1; index += 1) {
    chunks.push({ start: bounds[index], end: bounds[index + 1] });
  }
  return chunks;
}

function rankWithinParty(personId, partyId, monthValue, people) {
  if (!partyId) {
    return 0;
  }
  const cohort = people.filter((person) => primaryPartyAt(person, monthValue) === partyId);
  const sorted = cohort.slice().sort((left, right) => {
    const leftScore = Math.abs(scoreOnDate(left, monthValue));
    const rightScore = Math.abs(scoreOnDate(right, monthValue));
    if (leftScore !== rightScore) {
      return leftScore - rightScore;
    }
    return (left.name || "").localeCompare(right.name || "");
  });
  return Math.max(0, sorted.findIndex((person) => person.id === personId));
}

function guideSlotFromRank(rank) {
  if (guideLineCount <= 0) {
    return 0;
  }
  return Math.min(Math.max(1, rank + 1), guideLineCount);
}

