function rankAmongIndependents(personId, monthValue, people) {
  const cohort = people.filter((person) => !primaryPartyAt(person, monthValue));
  const sorted = cohort.slice().sort((left, right) => {
    const leftScore = Math.abs(scoreOnDate(left, monthValue));
    const rightScore = Math.abs(scoreOnDate(right, monthValue));
    if (leftScore !== rightScore) {
      return leftScore - rightScore;
    }
    return (left.name || "").localeCompare(right.name || "");
  });
  return Math.max(0, sorted.findIndex((person) => person.id === personId));
}

function renderActorsLayer() {
  if (!partyBandsLayer || !personalitiesLayer) {
    return;
  }
  partyBandsLayer.innerHTML = "";
  personalitiesLayer.innerHTML = "";
  personalityShapes.length = 0;

  parties.forEach((party) => {
    const range = partyActivityRange(party);
    const startMonth = numberToMonth(range.start);
    const endMonth = numberToMonth(range.end);

    const topProgress = dateToProgress(parseMonth(startMonth));
    const bottomProgress = dateToProgress(parseMonth(endMonth));
    const height = Math.max(0.15, (bottomProgress - topProgress) * 100);

    const members = personalities.filter((person) => (person.partyAffiliations || []).some((row) => row.partyId === party.id));
    let minOffset = 0;
    let maxOffset = 0;
    if (!members.length) {
      minOffset = -6;
      maxOffset = 6;
    }

    members.forEach((person) => {
      lifeChunks(person).forEach((chunk) => {
        const mid = midMonth(chunk.start, chunk.end);
        if (primaryPartyAt(person, mid) !== party.id) {
          return;
        }
        const score = scoreOnDate(person, mid);
        const sign = score === 0 ? 0 : score > 0 ? 1 : -1;
        const progress = dateToProgress(parseMonth(mid));
        let offset = 0;
        if (sign === 0) {
          minOffset = Math.min(minOffset, -14);
          maxOffset = Math.max(maxOffset, 14);
          return;
        }
        const rank = rankWithinParty(person.id, party.id, mid, personalities);
        const slot = guideSlotFromRank(rank);
        offset = perpendicularOffsetPx(progress, slot, sign);
        minOffset = Math.min(minOffset, offset - 12.5);
        maxOffset = Math.max(maxOffset, offset + 12.5);
      });
    });

    const center = (minOffset + maxOffset) / 2;
    const widthPx = Math.max(10, maxOffset - minOffset + 10);

    const band = document.createElement("div");
    band.className = "party-band";
    band.style.top = `${topProgress * 100}%`;
    band.style.height = `${height}%`;
    band.style.width = `${widthPx}px`;
    band.style.transform = `translate(calc(-50% + ${center}px), 0) rotate(var(--line-angle))`;
    band.title = party.name;
    const partyLabel = document.createElement("span");
    partyLabel.className = "bar-label";
    partyLabel.textContent = party.name;
    band.append(partyLabel);
    partyBandsLayer.append(band);
  });

  const svgNs = "http://www.w3.org/2000/svg";

  personalities.forEach((person) => {
    lifeChunks(person).forEach((chunk) => {
      const mid = midMonth(chunk.start, chunk.end);
      const partyId = primaryPartyAt(person, mid);
      const score = scoreOnDate(person, mid);
      const sign = score === 0 ? 0 : score > 0 ? 1 : -1;
      const birthProgress = dateToProgress(parseMonth(chunk.start));
      const deathProgress = dateToProgress(parseMonth(chunk.end));

      let slot = 1;
      if (sign !== 0 && guideLineCount > 0) {
        const rank = partyId
          ? rankWithinParty(person.id, partyId, mid, personalities)
          : rankAmongIndependents(person.id, mid, personalities);
        slot = guideSlotFromRank(rank);
      }

      const svg = document.createElementNS(svgNs, "svg");
      svg.classList.add("personality-shape");
      svg.dataset.side = sign > 0 ? "right" : sign < 0 ? "left" : "center";
      svg.dataset.pbirth = String(birthProgress);
      svg.dataset.pdeath = String(deathProgress);
      svg.dataset.slot = String(slot);
      svg.dataset.sign = String(sign);
      svg.dataset.name = person.name;

      const svgTitle = document.createElementNS(svgNs, "title");
      svgTitle.textContent = `${person.name} (${chunk.start}–${chunk.end})`;
      const poly = document.createElementNS(svgNs, "polygon");
      poly.setAttribute("class", "personality-poly");
      const textEl = document.createElementNS(svgNs, "text");
      textEl.setAttribute("class", "personality-label");
      svg.append(svgTitle, poly, textEl);
      personalitiesLayer.append(svg);
      personalityShapes.push({
        svg,
        poly,
        label: textEl,
        pBirth: birthProgress,
        pDeath: deathProgress,
        pMid: (birthProgress + deathProgress) / 2,
        slot,
        sign,
        name: person.name || ""
      });
    });
  });
}

