function initializePerspectiveDepthControl() {
  if (!perspectiveDepthInput) {
    return;
  }
  perspectiveDepthInput.value = perspectiveDepth.toFixed(2);
  updatePerspectiveDepthLabel();
  updateTimelineLineProfile();
  applyScrollableSpanForTimeFactor();
  perspectiveDepthInput.addEventListener("pointerdown", () => {
    perspectiveAnchorDate = progressToDate(getScrollProgress());
  });
  perspectiveDepthInput.addEventListener("pointerup", () => {
    perspectiveAnchorDate = null;
  });
  perspectiveDepthInput.addEventListener("change", () => {
    perspectiveAnchorDate = null;
  });
  perspectiveDepthInput.addEventListener("input", () => {
    const fixedCenterDate = perspectiveAnchorDate || progressToDate(getScrollProgress());
    perspectiveDepth = clamp(Number(perspectiveDepthInput.value), 1, 3);
    timelineSettings.perspectiveDepth = perspectiveDepth;
    window.TiltingLineStore.save(appData);
    updatePerspectiveDepthLabel();
    updateTimelineLineProfile();
    applyScrollableSpanForTimeFactor();
    renderYearMarkers();
    renderEvents();
    const maxScroll = document.documentElement.scrollHeight - window.innerHeight;
    const anchoredProgress = clamp(dateToDisplayProgressUnclamped(fixedCenterDate), 0, 1);
    const targetTop = Math.max(0, anchoredProgress * maxScroll);
    window.scrollTo(0, targetTop);
    document.documentElement.scrollTop = targetTop;
    document.body.scrollTop = targetTop;
    window.requestAnimationFrame(updateTimeline);
  });
}

